CREATE OR REPLACE FUNCTION OFSERM.INSIGNFCNT_INVSTMNT_CAP_DEDUCTION_EXPOSURES(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DEDUCTION_EXPOSURES(N_RUN_SKEY,N_ACCT_SKEY,N_CAP_COMP_GROUP_SKEY,N_DRAWN_EAD_PRE_MITIGATION,N_DVA_AMOUNT,N_EAD_PRE_MITIGATION,N_EL_AMOUNT,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_DED_AMT,N_EXP_MTM_VALUE,N_GAAP_SKEY,N_INCURRED_CVA_AMOUNT,N_INSTR_OTH_VALUATION_ADJ_AMT,N_INSTR_VALUATION_ADJ_AMOUNT,N_LEVERAGE_EXPOSURE_AMOUNT,N_MIS_DATE_SKEY,N_NOTIONAL_PRINCIPAL,N_OTC_DERIVATIVE_MULTIPLIER,N_OTHER_VALUATION_ADJ_AMT,N_POTENTIAL_ESTIMATE_LOSS,N_PRE_CRM_POST_VOL_HC_EAD,N_PRE_MITIGATION_CAPITAL_UL,N_PRE_MITIGATION_EL_AMT,N_PRE_MITIGATION_RWA_UL,N_PROVISION_AMOUNT,N_RWA_UL_AMT,N_SIG_INSIG_STD_ACCT_HEAD_SKEY,N_STD_ACCT_HEAD_SKEY,N_UNDRAWN_AMOUNT,N_UNDRAWN_EAD_PRE_MITIGATION,N_UNPAID_PREMIUM,N_VALUATION_ADJ_AMOUNT)SELECT  /*+PARALLEL (4)*/ to_char(DIM_RUN.N_RUN_SKEY),INSIGNFCNT_INVSTMNT.N_ACCT_SKEY,INSIGNFCNT_INVSTMNT.N_CAP_COMP_GROUP_SKEY,INSIGNFCNT_INVSTMNT.N_DRAWN_EAD_PRE_MITIGATION,INSIGNFCNT_INVSTMNT.N_DVA_AMOUNT,INSIGNFCNT_INVSTMNT.N_EAD_PRE_MITIGATION,INSIGNFCNT_INVSTMNT.N_EL_AMOUNT,INSIGNFCNT_INVSTMNT.N_EXPOSURE_AMOUNT,INSIGNFCNT_INVSTMNT.N_EXP_COVERED_AMT,INSIGNFCNT_INVSTMNT.N_EXP_DED_AMT,INSIGNFCNT_INVSTMNT.N_EXP_MTM_VALUE,INSIGNFCNT_INVSTMNT.N_GAAP_SKEY,INSIGNFCNT_INVSTMNT.N_INCURRED_CVA_AMOUNT,INSIGNFCNT_INVSTMNT.N_INSTR_OTH_VALUATION_ADJ_AMT,INSIGNFCNT_INVSTMNT.N_INSTR_VALUATION_ADJ_AMOUNT,INSIGNFCNT_INVSTMNT.N_LEVERAGE_EXPOSURE_AMOUNT,INSIGNFCNT_INVSTMNT.N_MIS_DATE_SKEY,INSIGNFCNT_INVSTMNT.N_NOTIONAL_PRINCIPAL,INSIGNFCNT_INVSTMNT.N_OTC_DERIVATIVE_MULTIPLIER,INSIGNFCNT_INVSTMNT.N_OTHER_VALUATION_ADJ_AMT,INSIGNFCNT_INVSTMNT.N_POTENTIAL_ESTIMATE_LOSS,INSIGNFCNT_INVSTMNT.N_PRE_CRM_POST_VOL_HC_EAD,INSIGNFCNT_INVSTMNT.N_PRE_MITIGATION_CAPITAL_UL,INSIGNFCNT_INVSTMNT.N_PRE_MITIGATION_EL_AMT,INSIGNFCNT_INVSTMNT.N_PRE_MITIGATION_RWA_UL,INSIGNFCNT_INVSTMNT.N_PROVISION_AMOUNT,INSIGNFCNT_INVSTMNT.N_RWA_UL_AMT,CASE WHEN INSIGNFCNT_INVSTMNT.V_CAP_COMP_GROUP_CODE = 'CET1COMP' THEN ( SELECT DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY FROM DIM_STANDARD_ACCT_HEAD WHERE DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = 'CAP918' AND to_date('20260331','YYYYMMDD') BETWEEN DIM_STANDARD_ACCT_HEAD.D_RECORD_START_DATE AND DIM_STANDARD_ACCT_HEAD.D_RECORD_END_DATE ) WHEN INSIGNFCNT_INVSTMNT.V_CAP_COMP_GROUP_CODE = 'AT1COMP' THEN ( SELECT DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY FROM DIM_STANDARD_ACCT_HEAD WHERE DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = 'CAP919' AND to_date('20260331','YYYYMMDD') BETWEEN DIM_STANDARD_ACCT_HEAD.D_RECORD_START_DATE AND DIM_STANDARD_ACCT_HEAD.D_RECORD_END_DATE ) WHEN INSIGNFCNT_INVSTMNT.V_CAP_COMP_GROUP_CODE = 'T2COMP' THEN ( SELECT DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY FROM DIM_STANDARD_ACCT_HEAD WHERE DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = 'CAP920' AND to_date('20260331','YYYYMMDD') BETWEEN DIM_STANDARD_ACCT_HEAD.D_RECORD_START_DATE AND DIM_STANDARD_ACCT_HEAD.D_RECORD_END_DATE ) END,INSIGNFCNT_INVSTMNT.N_STD_ACCT_HEAD_SKEY,INSIGNFCNT_INVSTMNT.N_UNDRAWN_AMOUNT,INSIGNFCNT_INVSTMNT.N_UNDRAWN_EAD_PRE_MITIGATION,INSIGNFCNT_INVSTMNT.N_UNPAID_PREMIUM,INSIGNFCNT_INVSTMNT.N_VALUATION_ADJ_AMOUNT FROM ( SELECT FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_ACCT_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_STD_ACCT_HEAD_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_COMP_GROUP_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_DED_AMT ,FSI_CAP_INVESTMENT_EXPOSURES.N_DRAWN_EAD_PRE_MITIGATION ,NULL N_DVA_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_EAD_PRE_MITIGATION ,FSI_CAP_INVESTMENT_EXPOSURES.N_EL_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_COVERED_AMT ,FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_MTM_VALUE ,NULL N_INCURRED_CVA_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_OTH_VALUATION_ADJ_AMT ,FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_VALUATION_ADJ_AMOUNT ,NULL N_NOTIONAL_PRINCIPAL ,NULL N_OTC_DERIVATIVE_MULTIPLIER ,FSI_CAP_INVESTMENT_EXPOSURES.N_OTHER_VALUATION_ADJ_AMT ,FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_CRM_POST_VOL_HC_EAD ,FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_CAPITAL_UL ,FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_EL_AMT ,FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_RWA_UL ,FSI_CAP_INVESTMENT_EXPOSURES.N_PROVISION_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_RWA_UL_AMT ,NULL N_UNPAID_PREMIUM ,FSI_CAP_INVESTMENT_EXPOSURES.N_VALUATION_ADJ_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_EXPOSURE_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_LEVERAGE_EXPOSURE_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_POTENTIAL_ESTIMATE_LOSS ,FSI_CAP_INVESTMENT_EXPOSURES.N_UNDRAWN_AMOUNT ,FSI_CAP_INVESTMENT_EXPOSURES.N_UNDRAWN_EAD_PRE_MITIGATION ,DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE FROM FSI_CAP_INVESTMENT_EXPOSURES LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY INNER JOIN DIM_CAPITAL_COMP_GROUP ON DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY = COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_COMP_GROUP_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_UNDERLYING_CAP_COMP_GRP_SKEY)   AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE IN ( 'CET1COMP' ,'AT1COMP' ,'T2COMP' ) LEFT OUTER JOIN DIM_EXPOSURE DED_EXPOSURE ON DED_EXPOSURE.N_ACCT_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_ACCT_SKEY INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_PARTY_SKEY = COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_ISSUER_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_SKEY) AND FCT_ENTITY_INFO.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY AND COALESCE(FCT_ENTITY_INFO.F_REGULATORY_ENTITY_IND, 'N') = 'N' LEFT OUTER JOIN FSI_NON_REG_CONSL_ENTITY_INVST ON FSI_NON_REG_CONSL_ENTITY_INVST.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_MIS_DATE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_PARTY_SKEY = COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_ISSUER_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_SKEY) LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_STD_ACCT_HEAD_SKEY WHERE 1 = 1 AND FSI_CAP_INVESTMENT_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND = 'N' AND COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.F_SUPERVISORY_DED_EXCLUSION, 'N') = 'N' AND FSI_CAP_INVESTMENT_EXPOSURES.N_PARENT_ACCT_SKEY IS NULL AND ( ( DIM_RUN.V_JURISDICTION_CODE = 'THAI' AND ( DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID NOT IN ( 'CAP1187' ,'CAP1190' ,'CAP1193' ) OR DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IS NULL ) /*BOT*/ ) OR DIM_RUN.V_JURISDICTION_CODE != 'THAI' ) UNION ALL SELECT FSI_CAP_DERIVATIVES.N_RUN_SKEY ,FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY ,FSI_CAP_DERIVATIVES.N_ACCT_SKEY ,FSI_CAP_DERIVATIVES.N_GAAP_SKEY ,FSI_CAP_DERIVATIVES.N_STD_ACCT_HEAD_SKEY ,FSI_CAP_DERIVATIVES.N_CAP_COMP_GROUP_SKEY ,FSI_CAP_DERIVATIVES.N_EXP_DED_AMT ,FSI_CAP_DERIVATIVES.N_DRAWN_EAD_PRE_MITIGATION ,FSI_CAP_DERIVATIVES.N_DVA_AMOUNT ,FSI_CAP_DERIVATIVES.N_EAD_PRE_MITIGATION ,FSI_CAP_DERIVATIVES.N_EL_AMOUNT ,FSI_CAP_DERIVATIVES.N_EXP_COVERED_AMT ,FSI_CAP_DERIVATIVES.N_EXP_MTM_VALUE ,FSI_CAP_DERIVATIVES.N_INCURRED_CVA_AMOUNT ,FSI_CAP_DERIVATIVES.N_INSTR_OTH_VALUATION_ADJ_AMT ,FSI_CAP_DERIVATIVES.N_INSTR_VALUATION_ADJ_AMOUNT ,FSI_CAP_DERIVATIVES.N_NOTIONAL_PRINCIPAL ,FSI_CAP_DERIVATIVES.N_OTC_DERIVATIVE_MULTIPLIER ,FSI_CAP_DERIVATIVES.N_OTHER_VALUATION_ADJ_AMT ,FSI_CAP_DERIVATIVES.N_PRE_CRM_POST_VOL_HC_EAD ,FSI_CAP_DERIVATIVES.N_PRE_MITIGATION_CAPITAL_UL ,FSI_CAP_DERIVATIVES.N_PRE_MITIGATION_EL_AMT ,FSI_CAP_DERIVATIVES.N_PRE_MITIGATION_RWA_UL ,FSI_CAP_DERIVATIVES.N_PROVISION_AMOUNT ,FSI_CAP_DERIVATIVES.N_RWA_UL_AMT ,FSI_CAP_DERIVATIVES.N_UNPAID_PREMIUM ,FSI_CAP_DERIVATIVES.N_VALUATION_ADJ_AMOUNT ,FSI_CAP_DERIVATIVES.N_EXPOSURE_AMOUNT ,NULL N_LEVERAGE_EXPOSURE_AMOUNT ,NULL N_POTENTIAL_ESTIMATE_LOSS ,FSI_CAP_DERIVATIVES.N_UNDRAWN_AMOUNT ,FSI_CAP_DERIVATIVES.N_UNDRAWN_EAD_PRE_MITIGATION ,DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE FROM FSI_CAP_DERIVATIVES INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY INNER JOIN DIM_CAPITAL_COMP_GROUP ON DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY = COALESCE(FSI_CAP_DERIVATIVES.N_CAP_COMP_GROUP_SKEY, FSI_CAP_DERIVATIVES.N_UNDERLYING_CAP_COMP_GRP_SKEY) AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE IN ( 'CET1COMP' ,'AT1COMP' ,'T2COMP' ) LEFT OUTER JOIN DIM_EXPOSURE DED_EXPOSURE ON DED_EXPOSURE.N_ACCT_SKEY = FSI_CAP_DERIVATIVES.N_ACCT_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_PARTY_SKEY = FSI_CAP_DERIVATIVES.N_CUST_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_NON_REG_CONSL_ENTITY_INVST ON FSI_NON_REG_CONSL_ENTITY_INVST.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FSI_NON_REG_CONSL_ENTITY_INVST.N_PARTY_SKEY = FSI_CAP_DERIVATIVES.N_CUST_SKEY LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FSI_CAP_DERIVATIVES.N_STD_ACCT_HEAD_SKEY WHERE 1 = 1 AND COALESCE(FCT_ENTITY_INFO.F_REGULATORY_ENTITY_IND, 'N') = 'N' AND FSI_CAP_DERIVATIVES.F_SIGNIFICANT_INVESTMENT_IND = 'N' AND COALESCE(FSI_CAP_DERIVATIVES.F_SUPERVISORY_DED_EXCLUSION, 'N') = 'N' AND FSI_CAP_DERIVATIVES.N_PARENT_ACCT_SKEY IS NULL AND ( ( DIM_RUN.V_JURISDICTION_CODE = 'THAI' AND ( DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID NOT IN ( 'CAP1187' ,'CAP1190' ,'CAP1193' ) OR DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IS NULL ) /*BOT*/ ) OR DIM_RUN.V_JURISDICTION_CODE != 'THAI' ) ) INSIGNFCNT_INVSTMNT INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = INSIGNFCNT_INVSTMNT.N_RUN_SKEY WHERE 1=1 AND 1=1 LOG ERRORS INTO FSI_CAP_DEDUCTION_EXPOSURES$ ('1776771842524_98892722_20260331_1_Job_06d5593b72c2494e9db4cfab7bbe2914') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

